mapper.select:
SELECT * FROM links 
WHERE user_id = #{userId}

  AND (
    short_code LIKE '%' || #{search} || '%'
    OR default_target_url LIKE '%' || #{search} || '%'
    OR title LIKE '%' || #{search} || '%'
  )

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

mapper.insert:
INSERT INTO links (
  id, user_id, short_code, default_target_url, title, description, og_image, 
  fb_pixel_id, ga_tracking_id, custom_script, is_ad_enabled, ad_timer_seconds, 
  is_paywalled, price, clicks_count, expired_at
) VALUES (
  #{id}, #{userId}, #{shortCode}, #{defaultTargetUrl}, #{title}, #{description}, #{ogImage}, 
  #{fbPixelId}, #{gaTrackingId}, #{customScript}, #{isAdEnabled}, #{adTimerSeconds}, 
  #{isPaywalled}, #{price}, #{clicksCount}, #{expiredAt}
)

mapper.update:
UPDATE links
SET clicks_count = clicks_count + 1
WHERE id = #{id}

mapper.delete:
DELETE FROM links
WHERE expired_at IS NOT NULL
  AND expired_at < #{now}
